/**
 * Drizzle schema for ModelArena.
 *
 * Conventions:
 * - UUIDv4 primary keys, generated by the DB (`defaultRandom()`).
 * - Timestamps: `timestamp with time zone`, default `now()` on insert.
 *   `updatedAt` is intentionally NOT auto-updated by Drizzle — callers
 *   MUST set it explicitly on every UPDATE. This is a discipline decision:
 *   explicit writes are easier to audit than magic triggers.
 * - Immutable vote log: votes are never deleted or updated. Ratings are
 *   derived from votes and can be recomputed from scratch at any time.
 * - No global models catalog. `campaign_models` stores provider ids
 *   per-campaign. Cross-campaign aggregation depends on string equality of
 *   `provider_model_id`, which is why the UI must pick from a fixed
 *   catalog (see src/lib/models.ts) and never free-type.
 */
import {
  pgTable,
  pgEnum,
  text,
  uuid,
  timestamp,
  integer,
  numeric,
  jsonb,
  uniqueIndex,
  index,
} from 'drizzle-orm/pg-core';

export const campaignStatusEnum = pgEnum('campaign_status', [
  'draft',
  'active',
  'completed',
]);

export const voteWinnerEnum = pgEnum('vote_winner', [
  'A',
  'B',
  'tie',
  'both_bad',
]);

export const campaigns = pgTable('campaigns', {
  id: uuid('id').primaryKey().defaultRandom(),
  shareSlug: text('share_slug').notNull().unique(),
  name: text('name').notNull(),
  description: text('description').notNull().default(''),
  categories: text('categories').array().notNull().default([]),
  status: campaignStatusEnum('status').notNull().default('draft'),
  createdAt: timestamp('created_at', { withTimezone: true })
    .notNull()
    .defaultNow(),
  updatedAt: timestamp('updated_at', { withTimezone: true })
    .notNull()
    .defaultNow(),
  closedAt: timestamp('closed_at', { withTimezone: true }),
});

export const prompts = pgTable(
  'prompts',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    orderIndex: integer('order_index').notNull(),
    text: text('text').notNull(),
    context: text('context'),
    categoryTags: text('category_tags').array().notNull().default([]),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [index('prompts_campaign_order').on(t.campaignId, t.orderIndex)],
);

export const campaignModels = pgTable(
  'campaign_models',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    providerModelId: text('provider_model_id').notNull(),
    displayName: text('display_name').notNull(),
    params: jsonb('params').notNull().default({}),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_campaign_model').on(t.campaignId, t.providerModelId),
  ],
);

/**
 * One row per (prompt, campaign_model). Retry overwrites (UPSERT).
 * `output` is null until the generation completes; `error` is non-null if
 * it failed. Both-null means queued but not yet started.
 */
export const generations = pgTable(
  'generations',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    output: text('output'),
    tokensIn: integer('tokens_in'),
    tokensOut: integer('tokens_out'),
    latencyMs: integer('latency_ms'),
    costUsd: numeric('cost_usd', { precision: 12, scale: 8 }),
    providerResponseId: text('provider_response_id'),
    error: text('error'),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    completedAt: timestamp('completed_at', { withTimezone: true }),
  },
  (t) => [uniqueIndex('uniq_prompt_model').on(t.promptId, t.campaignModelId)],
);

/**
 * One row per (cookie, campaign). Same cookie visiting two campaigns
 * creates two participant rows — that's intentional; group-agreement
 * metrics are computed within a campaign.
 */
export const participants = pgTable(
  'participants',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    cookieId: uuid('cookie_id').notNull(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    email: text('email'),
    startedAt: timestamp('started_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    finishedAt: timestamp('finished_at', { withTimezone: true }),
  },
  (t) => [uniqueIndex('uniq_cookie_campaign').on(t.cookieId, t.campaignId)],
);

/**
 * Immutable. `pairKey` is the canonical form of (generationA, generationB),
 * lexicographically sorted then joined with ':'. Computed app-side before
 * insert. The unique index on (participantId, pairKey) enforces
 * one-vote-per-pair-per-participant regardless of which gen was shown as A
 * vs B.
 */
export const votes = pgTable(
  'votes',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    participantId: uuid('participant_id')
      .notNull()
      .references(() => participants.id, { onDelete: 'cascade' }),
    promptId: uuid('prompt_id')
      .notNull()
      .references(() => prompts.id, { onDelete: 'cascade' }),
    generationAId: uuid('generation_a_id')
      .notNull()
      .references(() => generations.id),
    generationBId: uuid('generation_b_id')
      .notNull()
      .references(() => generations.id),
    pairKey: text('pair_key').notNull(),
    winner: voteWinnerEnum('winner').notNull(),
    createdAt: timestamp('created_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (t) => [
    uniqueIndex('uniq_participant_pair').on(t.participantId, t.pairKey),
    index('votes_campaign').on(t.campaignId),
    index('votes_prompt').on(t.promptId),
  ],
);

/**
 * Denormalized per-category Elo + CI cache. Only GLOBAL ratings are stored
 * here — personal ratings are computed transiently on the results page.
 * `category` uses the sentinel string 'overall' to represent the
 * aggregate; per-category rows use the user-defined category tag.
 * CI columns are nullable until the first bootstrap pass.
 */
export const ratings = pgTable(
  'ratings',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    campaignId: uuid('campaign_id')
      .notNull()
      .references(() => campaigns.id, { onDelete: 'cascade' }),
    campaignModelId: uuid('campaign_model_id')
      .notNull()
      .references(() => campaignModels.id, { onDelete: 'cascade' }),
    category: text('category').notNull().default('overall'),
    elo: integer('elo').notNull().default(1000),
    ciLow: integer('ci_low'),
    ciHigh: integer('ci_high'),
    gameCount: integer('game_count').notNull().default(0),
    computedAt: timestamp('computed_at', { withTimezone: true })
      .notNull()
      .defaultNow(),
    ciComputedAt: timestamp('ci_computed_at', { withTimezone: true }),
  },
  (t) => [
    uniqueIndex('uniq_rating').on(
      t.campaignId,
      t.campaignModelId,
      t.category,
    ),
  ],
);

// Types exported for use in API handlers and helpers.
export type Campaign = typeof campaigns.$inferSelect;
export type NewCampaign = typeof campaigns.$inferInsert;
export type Prompt = typeof prompts.$inferSelect;
export type NewPrompt = typeof prompts.$inferInsert;
export type CampaignModel = typeof campaignModels.$inferSelect;
export type NewCampaignModel = typeof campaignModels.$inferInsert;
export type Generation = typeof generations.$inferSelect;
export type NewGeneration = typeof generations.$inferInsert;
export type Participant = typeof participants.$inferSelect;
export type NewParticipant = typeof participants.$inferInsert;
export type Vote = typeof votes.$inferSelect;
export type NewVote = typeof votes.$inferInsert;
export type Rating = typeof ratings.$inferSelect;
export type NewRating = typeof ratings.$inferInsert;
